def _parse_transform_substr(substr):
    name, _, args = substr.strip().partition("(")
    name = name.strip()
    values = [float(v) for v in re.split(r"[\s,]+", args.strip()) if v]

    if name == "translate":
        tx = values[0]
        ty = values[1] if len(values) > 1 else 0.0
        return np.array([[1, 0, tx], [0, 1, ty], [0, 0, 1]])
    if name == "scale":
        sx = values[0]
        sy = values[1] if len(values) > 1 else sx
        return np.array([[sx, 0, 0], [0, sy, 0], [0, 0, 1]])
    if name == "rotate":
        theta = np.radians(values[0])
        c, s = np.cos(theta), np.sin(theta)
        return np.array([[c, -s, 0], [s, c, 0], [0, 0, 1]])
    if name == "skewX":
        return np.array([[1, np.tan(np.radians(values[0])), 0], [0, 1, 0], [0, 0, 1]])
    if name == "skewY":
        return np.array([[1, 0, 0], [np.tan(np.radians(values[0])), 1, 0], [0, 0, 1]])
    if name == "matrix":
        a, b, c, d, e, f = values
        return np.array([[a, c, e], [b, d, f], [0, 0, 1]])
    raise ValueError("Unsupported transform: %s" % name)


