import re

_DERIVATIVE_PROG = re.compile(r"^d\(([^()]+)\)d\(([^()]+)\)$")


def parse_derivative_string(string, quantity_dict):
    match = _DERIVATIVE_PROG.match(string)
    if match is None:
        raise ValueError("string is not in the form of a derivative")
    varname, coordname = match.group(1), match.group(2)
    if varname not in quantity_dict or coordname not in quantity_dict:
        raise ValueError("variable in string not a valid quantity")
    return varname, coordname

